<?php
$pageTitle='Stock Counts';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('stock_counts');
$pdo=getDB();
$warehouses=$pdo->query('SELECT id,warehouse_name FROM '.table('warehouses').' ORDER BY warehouse_name')->fetchAll();$products=$pdo->query('SELECT id,sku,name FROM '.table('products').' ORDER BY name LIMIT 500')->fetchAll();$sessions=$pdo->query('SELECT s.*,w.warehouse_name FROM '.table('stock_count_sessions').' s LEFT JOIN '.table('warehouses').' w ON w.id=s.warehouse_id ORDER BY s.created_at DESC LIMIT 100')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)$_POST['action'];if($action==='session'){createStockCountSession($pdo,(int)$_POST['warehouse_id'],0,0,trim((string)$_POST['count_type']),trim((string)$_POST['notes']));flash('success','Stock count session started.');}elseif($action==='line'){addStockCountLine($pdo,(int)$_POST['session_id'],(int)$_POST['product_id'],max(0,(float)$_POST['counted_qty']),trim((string)$_POST['notes']));flash('success','Count line added.');}elseif($action==='adjustment'){createInventoryAdjustmentFromCount($pdo,(int)$_POST['session_id']);flash('success','Adjustment request created from variance.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'stock-counts']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/stock-counts.php');}
$lines=$pdo->query('SELECT l.*,s.count_number,p.sku,p.name FROM '.table('stock_count_lines').' l LEFT JOIN '.table('stock_count_sessions').' s ON s.id=l.stock_count_session_id LEFT JOIN '.table('products').' p ON p.id=l.product_id ORDER BY l.created_at DESC LIMIT 150')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Physical Inventory</div><h2 class="h4 mb-1">Stock Counts</h2><p class="text-secondary mb-0">Run cycle counts, capture counted quantity, variance, and create adjustment requests.</p></div></div><div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="session"><h2 class="h5 mb-3">Start Count</h2><select class="form-select mb-2" name="warehouse_id"><?php foreach($warehouses as $w): ?><option value="<?php echo (int)$w['id']; ?>"><?php echo esc($w['warehouse_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="count_type"><option value="cycle">Cycle Count</option><option value="full">Full Count</option><option value="spot">Spot Check</option></select><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Start Session</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="line"><h2 class="h5 mb-3">Add Count Line</h2><select class="form-select mb-2" name="session_id"><?php foreach($sessions as $s): ?><option value="<?php echo (int)$s['id']; ?>"><?php echo esc($s['count_number']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="product_id"><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['sku'].' · '.$p['name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" type="number" step="0.0001" name="counted_qty" placeholder="Counted quantity"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Add Line</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Sessions</h2><table class="table"><thead><tr><th>Count</th><th>Warehouse</th><th>Type</th><th>Status</th><th>Adjustment</th></tr></thead><tbody><?php foreach($sessions as $s): ?><tr><td><strong><?php echo esc($s['count_number']); ?></strong></td><td><?php echo esc($s['warehouse_name']); ?></td><td><?php echo esc($s['count_type']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($s['status'])); ?>"><?php echo esc($s['status']); ?></span></td><td><form method="post"><input type="hidden" name="action" value="adjustment"><input type="hidden" name="session_id" value="<?php echo (int)$s['id']; ?>"><button class="btn btn-sm btn-success">Create Adjustment</button></form></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Count Lines</h2><table class="table"><thead><tr><th>Session</th><th>Product</th><th>System</th><th>Counted</th><th>Variance</th><th>Value</th></tr></thead><tbody><?php foreach($lines as $l): ?><tr><td><?php echo esc($l['count_number']); ?></td><td><?php echo esc($l['sku'].' · '.$l['name']); ?></td><td><?php echo number_format((float)$l['system_qty'],4); ?></td><td><?php echo number_format((float)$l['counted_qty'],4); ?></td><td><?php echo number_format((float)$l['variance_qty'],4); ?></td><td><?php echo money($l['variance_value']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>